let data = msg.payload;
if (typeof data === "string") {
    try {
        data = JSON.parse(data);
    } catch (e) {
        node.warn("Prediction payload is not valid JSON");
        return null;
    }
}

if (!data || typeof data !== "object") {
    return null;
}

const topicParts = String(msg.topic || "").split("/");
const topicSite = topicParts[1] || "sitea";
const topicFloor = topicParts[2] || "floor1";
const topicLine = topicParts[3] || "line1";
const topicCell = topicParts[4] || "cell1";
const topicLampId = topicParts[5] || "unknown_lamp";

const meta = data.meta || {};
const prediction = data.failure_prediction || {};
const fault = data.fault_classification || {};
const alert = data.alert || {};
const status = data.current_status || {};

const p3 = prediction.probability_3_days;
const p7 = prediction.probability_7_days;
const p14 = prediction.probability_14_days;

const faultLabel = String(fault.fault_label || data.fault_label || "Unknown");
const severity = String(alert.severity || data.severity || "NONE");
const alertType = String(alert.alert_type || data.alert_type || "NONE");
const currentState = String(status.state || data.current_state || "UNKNOWN");

const fields = {
    failure_prob_3d: Number(p3 == null ? 0 : p3),
    failure_prob_7d: Number(p7 == null ? 0 : p7),
    failure_prob_14d: Number(p14 == null ? 0 : p14),
    estimated_remaining_days: Number(prediction.estimated_remaining_days == null ? -1 : prediction.estimated_remaining_days),
    fault_type: Number(fault.predicted_fault_type == null ? -1 : fault.predicted_fault_type),
    health_score: Number(status.health_score == null ? 0 : status.health_score),
    fault_label_text: faultLabel,
    severity_text: severity,
    alert_type_text: alertType,
    current_state_text: currentState
};

const tags = {
    fault_label: faultLabel,
    severity: severity,
    alert_type: alertType,
    current_state: currentState,
    lamp_id: String(meta.luminaireId || data.bulb_id || topicLampId),
    site: String(meta.site || topicSite),
    floor: String(meta.floor || topicFloor),
    line: String(meta.line || topicLine),
    cell: String(meta.cell || topicCell),
    source: "ml"
};

msg.payload = [fields, tags];
return msg;

